2. Поменять в коде пару конфигов (color, line_style, line_width, title... etc)
3. Навести курсор на пилюлю индикатора на графике и нажать на кнопку апдейта
проверочный код
```
from math import isclose 
from indie import indicator, format, ctx, series, param, plot, color, level, line_style
from indie.algorithm import ema


@indicator('TP-1248', format=format.VOLUME)
@plot(color=color.RED)
@level(100, line_color=color.GRAY)
@level(0, line_color=color.PURPLE, line_style=line_style.DOTTED, line_width = 2)
def main():
    h = ctx.high[0]
    l = ctx.low[0]
    c = ctx.close[0]
    v = ctx.volume[0]

    money_flow_volume = 0.0
    if not isclose(h - l, 0):
        money_flow_volume = ((c - l) - (h - c)) / (h - l) * v

    adl = series(init=0)
    adl[0] += money_flow_volume

    ch_osc = ema(adl, 3)[0] - ema(adl, 10)[0]
    return ch_osc
```

```
from indie import indicator, param, source, plot, color, fill, Plot, Fill, line_style
from indie.algorithm import bb


# Bollinger Bands
@indicator('BB', overlay_main_pane=True)
#Settings
@param.int('length', default=30, min=1, title='Lenght 12345')
@param.source('src', default=source.OPEN, title='Source 12345')
@param.float('mult', default=5.0, min=0.001, max=50.0, title='StdDev 12345')
@param.int('offset', default=1, min=-500, max=500, title='Offset 12345')
#Style
@plot('lower', color=color.WHITE, line_style=line_style.DASHED, title='Lower 12345')
@plot(color=color.WHITE, line_style=line_style.DOTTED ,title='Basis 12345', line_width=4)
@plot('upper', color=color.WHITE, title='Upper 12345')
@fill('lower', 'upper', color=color.WHITE(0.05), title='Background Ruslan 12345')
def main(length, src, mult, offset):
    (lower, middle, upper) = bb(src, length, mult)
    return (
        Plot(lower[0], offset=offset),
        Plot(middle[0], offset=offset),
        Plot(upper[0], offset=offset),
        Fill(),
    )
```



